understanding_answer:
**תשובה מלאה לסעיף 3 – יצירת מורה דרך API (POST)**  
*הנחיות מבחן: תשובת מבחן מלאה – כולל הבנת הדרישה, פתרון/קוד, הסבר, מלכודת נפוצה, בדיקת תקינות.*

---

### ✅ **1. הבנת הדרישה**
המשתמש מבקש לשלוח בקשת `POST` ל-`/teachers` עם נתוני מורה (למשל: שם, מקצוע).  
המערכת חייבת:
- **לבדוק אם כבר קיים מורה עם אותו שם + אותו מקצוע** – אם כן, להחזיר שגיאה (למשל 409 Conflict).
- **אם לא קיים**, להכניס את המורה ל-DB.
- להחזיר **201 Created** עם הנתונים שהוכנסו (או הודעה מובנית).
- לספק ממשק משתמש (UI) שמאפשר לשלוח את הבקשה ולראות את התוצאה (הצגת הודעה/נתונים).
- **לטפל בשגיאות** (DB, ולידציה, שגיאות לא צפויות) – ללא הסתרת כשלונות.

---

### ✅ **2. פתרון – קוד API (Node.js + Express + PostgreSQL/MySQL)**

#### 📁 מבנה הבקשה (Request)
```http
POST /teachers
Content-Type: application/json

{
  "name": "דבורה כהן",
  "subject": "מתמטיקה"
}
```

#### 📦 קובץ ה-API (server.js / routes/teachers.js)
```javascript
const express = require('express');
const router = express.Router();
const db = require('../db'); // חיבור ל-DB (למשל: pg או mysql2)

// בדיקת ולידציה בסיסית
const validateTeacher = (data) => {
  if (!data.name || typeof data.name !== 'string' || data.name.trim().length === 0) {
    return { valid: false, error: 'שם חסר או לא תקין' };
  }
  if (!data.subject || typeof data.subject !== 'string' || data.subject.trim().length === 0) {
    return { valid: false, error: 'מקצוע חסר או לא תקין' };
  }
  return { valid: true };
};

// POST /teachers
router.post('/', async (req, res) => {
  try {
    // 1. קריאה מ-req.body
    const { name, subject } = req.body;

    // 2. ולידציה
    const validation = validateTeacher({ name, subject });
    if (!validation.valid) {
      return res.status(400).json({ error: validation.error });
    }

    // 3. בדיקה אם קיים כבר מורה עם אותו שם + מקצוע
    const existing = await db.query(
      'SELECT id FROM teachers WHERE name = $1 AND subject = $2',
      [name.trim(), subject.trim()]
    );

    if (existing.rows.length > 0) {
      return res.status(409).json({ 
        error: 'מורה עם שם ומקצוע זהים כבר קיים במערכת' 
      });
    }

    // 4. הכנסת המורה ל-DB
    const result = await db.query(
      'INSERT INTO teachers (name, subject) VALUES ($1, $2) RETURNING *',
      [name.trim(), subject.trim()]
    );

    // 5. החזרת 201 + הנתונים
    res.status(201).json({
      message: 'מורה נרשם בהצלחה',
      teacher: result.rows[0]
    });

  } catch (err) {
    // 6. טיפול בשגיאות – לא להסתיר!
    console.error('Error creating teacher:', err);
    res.status(500).json({ 
      error: 'שגיאה בשרת – לא ניתן לרשום את המורה' 
    });
  }
});

module.exports = router;
```

