  { id: 4, company: "EasyJet", destination: "London", time: "09:45" },
];

function FlightFilter() {
  const [companyFilter, setCompanyFilter] = useState("");
  const [filteredFlights, setFilteredFlights] = useState(initialFlights);

  const handleInputChange = (e) => {
    const value = e.target.value;
    setCompanyFilter(value);

    // סינון ללא mutation – יוצר מערך חדש
    const filtered = initialFlights.filter(flight =>
      flight.company.toLowerCase().includes(value.toLowerCase())
    );
    setFilteredFlights(filtered);
  };

  const handleSubmit = (e) => {
    e.preventDefault(); // מונע רענון דף
