import React, { useState, useEffect } from 'react';

const AddFlight = ({ onAddFlight, onNavigate }) => {
  const [flightNumber, setFlightNumber] = useState('');
  const [origin, setOrigin] = useState('');
  const [destination, setDestination] = useState('');
  const [errors, setErrors] = useState({});
  const [success, setSuccess] = useState(false);

  // Deterministic fixture data for origin/destination options
  const cities = [
    { code: 'TLV', name: 'Tel Aviv' },
    { code: 'JFK', name: 'New York' },
    { code: 'LHR', name: 'London' },
    { code: 'CDG', name: 'Paris' },
    { code: 'DXB', name: 'Dubai' }
  ];

  const handleSubmit = (e) => {
    e.preventDefault();

    const newErrors = {};
    if (!flightNumber.trim()) newErrors.flightNumber = 'Flight number is required';
    if (!origin) newErrors.origin = 'Origin is required';
    if (!destination) newErrors.destination = 'Destination is required';
    if (origin === destination) newErrors.destination = 'Origin and destination cannot be the same';

    setErrors(newErrors);

    if (Object.keys(newErrors).length === 0) {
      const newFlight = {
        id: `FL${Date.now()}`,
        flightNumber: flightNumber.trim().toUpperCase(),
        origin,
        destination,
        status: 'scheduled',
        departureTime: new Date().toISOString()
      };

      onAddFlight(newFlight);
      setSuccess(true);
      setFlightNumber('');
      setOrigin('');
      setDestination('');

      // Redirect after successful submission
      setTimeout(() => {
        setSuccess(false);
        onNavigate('/controlpanel');
      }, 2000);
    }
  };

  return (
    <div className="add-flight-container">
      <div className="sidebar">
        <nav>
          <button onClick={() => onNavigate('/controlpanel')} className="nav-btn">
            Dashboard
          </button>
          <button onClick={() => onNavigate('/controlpanel/add')} className="nav-btn active">
            Add Flight
          </button>
          <button onClick={() => onNavigate('/controlpanel/flights')} className="nav-btn">
            Manage Flights
          </button>
        </nav>
      </div>

      <div className="main-content">
        <h2>Add New Flight</h2>

        {success && (
          <div className="success-message">
            Flight added successfully! Redirecting...
          </div>
        )}

        <form onSubmit={handleSubmit} className="flight-form">
          <div className="form-group">
            <label htmlFor="flightNumber">Flight Number:</label>
            <input
              type="text"
              id="flightNumber"
              value={flightNumber}
              onChange={(e) => setFlightNumber(e.target.value)}
              placeholder="e.g., ELAL123"
              className={errors.flightNumber ? 'error' : ''}
            />
            {errors.flightNumber && <span className="error-text">{errors.flightNumber}</span>}
          </div>

          <div className="form-group">
            <label htmlFor="origin">Origin:</label>
            <select
              id="origin"
              value={origin}
              onChange={(e) => setOrigin(e.target.value)}
              className={errors.origin ? 'error' : ''}
            >
              <option value="">Select origin</option>
              {cities.map(city => (
                <option key={city.code} value={city.code}>{city.name} ({city.code})</option>
              ))}
            </select>
            {errors.origin && <span className="error-text">{errors.origin}</span>}
          </div>

          <div className="form-group">
            <label htmlFor="destination">Destination:</label>
            <select
              id="destination"
              value={destination}
              onChange={(e) => setDestination(e.target.value)}
              className={errors.destination ? 'error' : ''}
            >
              <option value="">Select destination</option>
              {cities.filter(city => city.code !== origin).map(city => (
                <option key={city.code} value={city.code}>{city.name} ({city.code})</option>
              ))}
            </select>
            {errors.destination && <span className="error-text">{errors.destination}</span>}
          </div>

          <button type="submit" className="add-btn">
            Add Flight
          </button>
        </form>
      </div>
    </div>
  );
};

export default AddFlight;
