import React, { useState, useEffect } from 'react';

const FlightNumberInput = ({ onValidSubmit, existingFlightNumbers = [123, 456, 789] }) => {
  const [flightNumber, setFlightNumber] = useState('');
  const [error, setError] = useState('');
  const [touched, setTouched] = useState(false);
  const [isSubmitting, setIsSubmitting] = useState(false);

  // Regex: exactly 1 to 5 digits
  const FLIGHT_NUMBER_REGEX = /^\d{1,5}$/;

  useEffect(() => {
    if (touched) {
      validateFlightNumber(flightNumber);
    }
  }, [flightNumber, touched]);

  const validateFlightNumber = (value) => {
    if (!value) {
      setError('שדה מספר טיסה הוא חובה');
      return false;
    }
    if (!FLIGHT_NUMBER_REGEX.test(value)) {
      setError('מספר טיסה חייב להיות בין 1 ל-5 ספרות');
      return false;
    }
    if (existingFlightNumbers.includes(parseInt(value, 10))) {
      setError('כבר קיימת טיסה עם מספר זה');
      return false;
    }
    setError('');
    return true;
  };

  const handleSubmit = (e) => {
    e.preventDefault();
    setTouched(true);

    if (validateFlightNumber(flightNumber)) {
      setIsSubmitting(true);
      // Simulate async save
      setTimeout(() => {
        onValidSubmit({ flightNumber: parseInt(flightNumber, 10) });
        setFlightNumber('');
        setError('');
        setIsSubmitting(false);
      }, 500);
    }
  };

  return (
    <form onSubmit={handleSubmit} className="max-w-md mx-auto p-4 bg-white rounded-lg shadow-md">
      <h2 className="text-xl font-bold mb-4">הוספת טיסה</h2>

      <div className="mb-4">
        <label htmlFor="flightNumber" className="block text-sm font-medium text-gray-700 mb-1">
          מספר טיסה
        </label>
        <input
          id="flightNumber"
          type="text"
          value={flightNumber}
          onChange={(e) => setFlightNumber(e.target.value.replace(/\D/g, ''))}
          onBlur={() => setTouched(true)}
          placeholder="הקלד מספר טיסה (1-5 ספרות)"
          className={`w-full px-3 py-2 border rounded-md focus:outline-none focus:ring-2 focus:ring-blue-500 ${
            error ? 'border-red-500' : 'border-gray-300'
          }`}
          maxLength={5}
          aria-invalid={!!error}
          aria-describedby={error ? 'flightNumber-error' : undefined}
        />
        {error && (
          <p id="flightNumber-error" className="mt-1 text-sm text-red-600">
            {error}
          </p>
        )}
        <p className="mt-1 text-xs text-gray-500">
          רק ספרות, עד 5 תווים. דוגמה: 12345
        </p>
      </div>

      <button
        type="submit"
        disabled={!!error || isSubmitting}
        className={`w-full py-2 px-4 rounded-md text-white font-medium transition-colors ${
          error || isSubmitting
            ? 'bg-gray-400 cursor-not-allowed'
            : 'bg-blue-600 hover:bg-blue-700 focus:outline-none focus:ring-2 focus:ring-blue-500'
        }`}
      >
        {isSubmitting ? 'שומר...' : 'הוסף טיסה'}
      </button>
    </form>
  );
};

export default FlightNumberInput;
```

