  <label for="passengers">מספר נוסעים:</label>
  <input 
    type="number" 
    id="passengers" 
    name="passengers" 
    min="1" 
    max="450" 
    required
    aria-describedby="passengers-error"
  >
  <span id="passengers-error" class="error-message" style="display: none; color: red;"></span>
</div>
<button type="submit" id="submit-btn">שליחה</button>
