#### ב. JavaScript – בדיקת תקינות (client-side validation)  
```javascript
document.getElementById('submit-btn').addEventListener('click', function(e) {
  const input = document.getElementById('passengers');
  const errorSpan = document.getElementById('passengers-error');
  const value = input.value.trim();

  // איפוס שגיאה
  errorSpan.style.display = 'none';
  errorSpan.textContent = '';

  // בדיקה אם השדה ריק
  if (value === '') {
    e.preventDefault();
    showError('שדה מספר נוסעים הוא חובה.');
    return;
  }

  // בדיקה אם זה מספר שלם
  if (!/^\d+$/.test(value)) {
    e.preventDefault();
    showError('יש להזין מספר שלם (ללא עשרוניים או תווים).');
    return;
  }

  // המרה למספר ובדיקת טווח
  const num = parseInt(value, 10);
  if (num < 1 || num > 450) {
    e.preventDefault();
    showError('מספר הנוסעים חייב להיות בין 1 ל-450.');
    return;
  }

  // אם כולם תקינים – אפשר לשלוח
  // (לא נזקק ל-e.preventDefault() – הsubmit יתבצע)
});

function showError(message) {
  const errorSpan = document.getElementById('passengers-error');
  errorSpan.textContent = message;
  errorSpan.style.display = 'inline';
  document.getElementById('passengers').classList.add('error-border');
}

// אופציונלי: בדיקה实时 (בזמן שהמשתמש מקליד)
document.getElementById('passengers').addEventListener('input', function() {
  this.classList.remove('error-border');
  document.getElementById('passengers-error').style.display = 'none';
});
```

