import React, { useState } from 'react';

function FlightNumberInput() {
  const [flightNumber, setFlightNumber] = useState('');
  const [error, setError] = useState('');

  // Regex: רק ספרות, עד 5 תווים
  const FLIGHT_REGEX = /^\d{0,5}$/;

  const handleChange = (e) => {
    const value = e.target.value;

    // בדיקה אם הערך תקין לפי ה-regex
    if (FLIGHT_REGEX.test(value)) {
      setFlightNumber(value);
      setError(''); // ניקוי שגיאה אם הערך תקין
    } else {
      // לא מעדכנים את הערך – שומרים את הערך הקודם
      setError('מספר טיסה חייב להיות עד 5 ספרות (ללא אותיות או סימנים)');
    }
  };

  const handleSubmit = (e) => {
    e.preventDefault();
    if (!flightNumber || flightNumber.length === 0) {
      setError('יש להזין מספר טיסה');
      return;
    }
    // כאן אפשר לשלוח לשרת – לדוגמה:
    console.log('נשלח מספר טיסה:', flightNumber);
  };

  return (
    <form onSubmit={handleSubmit}>
      <div>
        <label htmlFor="flight-number">מספר טיסה:</label>
        <input
          id="flight-number"
          type="text" // לא number – כדי לא לאפשר אוטומטית נקודות/פסיקים, ולשלוט ב-input ידנית
          value={flightNumber}
          onChange={handleChange}
          maxLength={5}
          placeholder="למשל: 1234"
          aria-invalid={!!error}
          aria-describedby={error ? 'flight-error' : undefined}
        />
        {error && (
          <div id="flight-error" style={{ color: 'red', marginTop: '4px' }}>
            {error}
          </div>
        )}
      </div>
      <button type="submit" disabled={!flightNumber}>
        שלח
      </button>
    </form>
  );
}

export default FlightNumberInput;
```

---

### ✅ **למה זה נכון?**
| רכיב | הסבר |
|------|-------|
| `type="text"` | לא `type="number"` – כי input מסוג `number` לא מאפשר בדיקת אורך מדויקת (אורך של `123` הוא 3, אבל `00123` יומר ל-`123`), ויכולה להכניס ערכים לא תקניים (כמו `1e5`). `text` נותן שליטה מלאה. |
