        return { valid: false, error: 'Invalid input: all terms must be numbers' };
      }
    }

    const difference = sequence[1] - sequence[0];
    for (let i = 1; i < sequence.length - 1; i++) {
      if (sequence[i + 1] - sequence[i] !== difference) {
