// sequenceType.js

function getSequenceType(arr) {
  // בדיקת קלט: חייב להיות מערך
  if (!Array.isArray(arr)) {
    throw new TypeError('Input must be an array.');
  }

  // בדיקת אורך מינימלי – לזכירת הסוגים, נחוצים לפחות 3 איברים
  if (arr.length < 3) {
    throw new Error('Array must contain at least 3 elements to determine sequence type.');
  }

  // בדיקת כל איבר – חייב להיות מספר (ולא NaN/Infinity)
  for (let i = 0; i < arr.length; i++) {
    const val = arr[i];
    if (typeof val !== 'number' || !Number.isFinite(val)) {
      throw new TypeError(`Invalid value at index ${i}: ${val} is not a finite number.`);
    }
  }

  // בדיקת סדרה חשבונית: הפרש קבוע
  const diff = arr[1] - arr[0];
  let isArithmetic = true;
  for (let i = 2; i < arr.length; i++) {
    if (arr[i] - arr[i - 1] !== diff) {
      isArithmetic = false;
      break;
    }
  }

  // בדיקת סדרה הנדסית: יחס קבוע (ולא אפס במכנה)
  let isGeometric = true;
  for (let i = 1; i < arr.length; i++) {
    if (arr[i - 1] === 0) {
      // אם יש איבר אפס, לא יכול להיות יחס קבוע (אלא אם כל השאר גם אפס – אבל אז זה לא הנדסית רגילה)
      isGeometric = false;
      break;
    }
    if (arr[i] / arr[i - 1] !== arr[1] / arr[0]) {
      isGeometric = false;
      break;
    }
  }

  // בדיקת פיבונאצי: arr[i] = arr[i-1] + arr[i-2]
  let isFibonacci = true;
  for (let i = 2; i < arr.length; i++) {
    if (arr[i] !== arr[i - 1] + arr[i - 2]) {
      isFibonacci = false;
      break;
    }
  }

  // חזרה לפי סדר העדיפות: פיבונאצי > חשבונית > הנדסית > אחר
  if (isFibonacci) return 'C';
  if (isArithmetic) return 'A';
  if (isGeometric) return 'B';
  return 'D';
}

